import{_ as o,o as r,c as i,a2 as s}from"./chunks/framework.D2pTuMig.js";const p=JSON.parse('{"title":"Bibliothèque","description":"","frontmatter":{"title":"Bibliothèque"},"headers":[],"relativePath":"docs/fr/resources/library.md","filePath":"docs/fr/resources/library.md"}'),a={name:"docs/fr/resources/library.md"};function t(n,e,d,l,c,u){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="bibliotheque-de-ressources" tabindex="-1">Bibliothèque de Ressources <a class="header-anchor" href="#bibliotheque-de-ressources" aria-label="Permalink to &quot;Bibliothèque de Ressources&quot;">​</a></h1><p>Accédez rapidement à tous les gabarits, logos et documents techniques nécessaires.</p><hr><h2 id="🎨-branding-logos" tabindex="-1">🎨 Branding &amp; Logos <a class="header-anchor" href="#🎨-branding-logos" aria-label="Permalink to &quot;🎨 Branding &amp; Logos&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>Logos Obligatoires</strong><p>Logo getinside · Triman · Info-tri (Loi AGEC). Formats <code>.ai</code> et <code>.png</code>.</p><a href="https://drive.google.com/drive/folders/1ORm6uAhsIWCCFWhOl-NjO4tKfiGQdLNy" target="_blank" class="btn btn-outline btn-sm">Accéder au Drive ↗</a></div></div><hr><h2 id="📐-gabarits-print-insertion-colis" tabindex="-1">📐 Gabarits Print (Insertion Colis) <a class="header-anchor" href="#📐-gabarits-print-insertion-colis" aria-label="Permalink to &quot;📐 Gabarits Print (Insertion Colis)&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>Pack Gabarits</strong><p>Formats A5 et A6 avec zones de fond perdu et zones tranquilles pré-tracées. Disponibles en <code>.ai</code> et <code>.pdf</code>.</p><a href="https://drive.google.com/drive/folders/1rbTKAXw8z-8xoy-_PhK9ICL_zb9do7xe" target="_blank" class="btn btn-primary btn-sm">Accéder au Drive ↗</a></div></div><div class="info custom-block"><p class="custom-block-title">Besoin d&#39;aide créative ?</p><p>Vous n&#39;avez pas les logiciels Adobe ? Déléguez la création à notre <a href="/handbook/docs/fr/resources/studio.html">Studio Graphique</a>. Forfait 550€ HT par campagne — contact : <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a></p></div><hr><h2 id="💻-logiciels-recommandes" tabindex="-1">💻 Logiciels Recommandés <a class="header-anchor" href="#💻-logiciels-recommandes" aria-label="Permalink to &quot;💻 Logiciels Recommandés&quot;">​</a></h2><p>Pour préparer vos visuels aux normes techniques, privilégiez les logiciels de PAO suivants :</p><div class="gi-value-grid"><div class="gi-value-card"><strong>Adobe Illustrator</strong><p>Création d&#39;illustrations vectorielles. Idéal pour exporter en <code>PDF/X</code> avec fond perdu inclus.</p></div><div class="gi-value-card"><strong>Adobe Photoshop</strong><p>Manipulation d&#39;images matricielles. Vérifiez résolution ≥ 300 DPI et mode colorimétrique CMJN.</p></div><div class="gi-value-card"><strong>Adobe InDesign</strong><p>Mise en page multi-pages avec export PDF/X et gestion du fond perdu automatique.</p></div></div><hr><h2 id="📄-documents-de-reference" tabindex="-1">📄 Documents de Référence <a class="header-anchor" href="#📄-documents-de-reference" aria-label="Permalink to &quot;📄 Documents de Référence&quot;">​</a></h2><ul><li><strong><a href="https://docs.google.com/document/d/17oybJkf4iOX0XrC4LOJSI0zp2y0w_Wn7F4GW_oBAZcM/edit" target="_blank">Check-list de Contrôle avant envoi ↗</a></strong> : À vérifier impérativement avant de soumettre un BAT.</li><li><strong><a href="/handbook/docs/fr/advertisers/sponsored-mail/design-guide/">Guide de Conception de Contenus</a></strong> : Toutes les règles techniques pour vos flyers (formats, résolution, mentions légales).</li></ul>',16)])])}const h=o(a,[["render",t]]);export{p as __pageData,h as default};
